 125 | async fn main() -> Result<()> {
 126 |     // Load .env files FIRST, so clap env variables are found during parse.
 127 |     // Priority (later wins): ~/.config/rust_agent/.env → ~/.env → CWD chain
 128 |     // This ensures a user-level .env in the home directory also works.
 129 |     if let Some(home) = dirs::home_dir() {
 130 |         // Lowest priority: ~/.config/rust_agent/.env (XDG-style)
 131 |         let xdg_env = dirs::config_dir()
 132 |             .unwrap_or_else(|| home.join(".config"))
 133 |             .join("rust_agent")
 134 |             .join(".env");
 135 |         dotenvy::from_path(&xdg_env).ok();
 136 | 
 137 |         // Medium priority: ~/.env
 138 |         dotenvy::from_path(home.join(".env")).ok();
 139 |     }
 140 |     // Highest priority: .env in CWD or its parents (standard dotenvy behavior)
 141 |     dotenvy::dotenv().ok();
 142 | 
 143 |     let args = Args::parse();
 144 | 
 145 |     // Initialize logging
 146 |     let filter = if args.verbose {
 147 |         EnvFilter::new("debug")
 148 |     } else {
 149 |         EnvFilter::new("warn")
 150 |     };
 151 |     tracing_subscriber::fmt()
 152 |         .with_env_filter(filter)
 153 |         .with_target(false)
 154 |         .init();
 155 | 
 156 |     // Set auto-approve if requested
 157 |     if args.auto_approve {
 158 |         confirm::set_auto_approve(true);
 159 |     }
 160 | 
 161 |     // Handle --sessions: list and exit
 162 |     if args.sessions {
 163 |         return cli::list_sessions_and_exit();
 164 |     }
 165 | 
 166 |     // Load config
 167 |     let config = config::Config::load(&args)?;
 168 | 
 169 |     // Determine project directory
 170 |     let project_dir = if let Some(ref workdir) = args.workdir {
 171 |         std::path::PathBuf::from(workdir)
 172 |             .canonicalize()
 173 |             .unwrap_or_else(|_| std::path::PathBuf::from(workdir))
 174 |     } else {
 175 |         std::env::current_dir().unwrap_or_default()
 176 |     };
 177 | 
 178 |     // Auto-spawn sub-agents configured in models.toml (if we're in CLI mode).
 179 |     // We keep the Child handles so we can kill the processes when the main agent exits.
 180 |     let mut spawned_children: Vec<std::process::Child> = Vec::new();
 181 |     if args.mode == RunMode::Cli && !config.sub_agents.is_empty() {
 182 |         spawned_children = spawn_sub_agents(&config, &project_dir);
 183 |     }
 184 | 
 185 |     // Server mode has its own event loop — launch and return
 186 |     if args.mode == RunMode::Server {
 187 |         return server::run(config, project_dir, &args.host, args.port).await;
 188 |     }
 189 | 
 190 |     // Build the output backend based on --mode
 191 |     let output: Arc<dyn output::AgentOutput> = match args.mode {
 192 |         RunMode::Cli => Arc::new(output::CliOutput::new()),
 193 |         RunMode::Stdio => Arc::new(output::StdioOutput::new()),
 194 |         RunMode::Server => unreachable!(), // handled above
 195 |     };
 196 | 
 197 |     // Run the agent
 198 |     let result = cli::run(config, project_dir, args.prompt, args.resume, output, args.sandbox, args.global_session).await;
 199 | 
 200 |     // Kill auto-spawned sub-agents so they don't become orphan processes.
 201 |     // On the next startup the ports would be occupied, causing port-bind failures.
 202 |     for mut child in spawned_children {
 203 |         let _ = child.kill();
 204 |         let _ = child.wait(); // reap to avoid zombie
 205 |     }
 206 | 
 207 |     result
 208 | }
