 210 | fn spawn_sub_agents(config: &config::Config, project_dir: &std::path::Path) -> Vec<std::process::Child> {
 211 |     use std::process::{Command, Stdio};
 212 | 
 213 |     let exe = std::env::current_exe().unwrap_or_else(|_| std::path::PathBuf::from("agent"));
 214 |     let mut children = Vec::new();
 215 | 
 216 |     for (name, sa) in &config.sub_agents {
 217 |         println!("🚀 Auto-spawning sub-agent '{}' on port {}...", name, sa.port);
 218 | 
 219 |         let mut cmd = Command::new(&exe);
 220 |         cmd.arg("--mode").arg("server")
 221 |            .arg("--port").arg(sa.port.to_string())
 222 |            .arg("-d").arg(project_dir)
 223 |            .env("AGENT_ROLE", "worker");
 224 | 
 225 |         match cmd.stdout(Stdio::null()).stderr(Stdio::null()).spawn() {
 226 |             Ok(child) => {
 227 |                 println!("✅ Sub-agent '{}' started (pid {}).", name, child.id());
 228 |                 children.push(child);
 229 |             }
 230 |             Err(e) => eprintln!("❌ Failed to spawn sub-agent '{}': {}", name, e),
 231 |         }
 232 |     }
 233 | 
 234 |     children
